 const clamp = (v, a, b) => Math.max(a, Math.min(b, v));
 const UNIFORM_ATOM_RADIUS = 10.5;
 const UNIFORM_BOND_WIDTH = 2.8;
 const deg = v => v * Math.PI / 180;
 const clone = v => JSON.parse(JSON.stringify(v));
 const mix = (a,b,t) => a + (b-a) * t;
 const smooth = t => t * t * (3 - 2 * t);

 function hexToRgb(hex){
 const s = String(hex || '#ffffff').replace('#','');
 const full = s.length === 3 ? s.split('').map(c => c + c).join('') : s.padEnd(6, '0');
 const n = parseInt(full, 16) || 0;
 return { r:(n>>16)&255, g:(n>>8)&255, b:n&255 };
 }
 function rgbToHex(r,g,b){
 const n = (clamp(r,0,255)<<16) | (clamp(g,0,255)<<8) | clamp(b,0,255);
 return '#' + n.toString(16).padStart(6,'0');
 }
 function shade(hex, amt){
 const c = hexToRgb(hex);
 const t = amt > 0 ? 255 : 0;
 const p = Math.abs(amt);
 return rgbToHex(
 Math.round(c.r + (t - c.r) * p),
 Math.round(c.g + (t - c.g) * p),
 Math.round(c.b + (t - c.b) * p)
 );
 }
 function rgba(hex, a){
 const c = hexToRgb(hex);
 return `rgba(${c.r},${c.g},${c.b},${a})`;
 }
 function lerpColor(a,b,t){
 const c1 = hexToRgb(a), c2 = hexToRgb(b);
 return rgbToHex(
 Math.round(mix(c1.r,c2.r,t)),
 Math.round(mix(c1.g,c2.g,t)),
 Math.round(mix(c1.b,c2.b,t))
 );
 }

 function rotX(v, a){ const s=Math.sin(a), c=Math.cos(a); return [v[0], c*v[1]-s*v[2], s*v[1]+c*v[2]]; }
 function rotY(v, a){ const s=Math.sin(a), c=Math.cos(a); return [c*v[0]+s*v[2], v[1], -s*v[0]+c*v[2]]; }
 function rotZ(v, a){ const s=Math.sin(a), c=Math.cos(a); return [c*v[0]-s*v[1], s*v[0]+c*v[1], v[2]]; }
 function add(a,b){ return [a[0]+b[0], a[1]+b[1], a[2]+b[2]]; }
 function sub(a,b){ return [a[0]-b[0], a[1]-b[1], a[2]-b[2]]; }
 function mul(v,s){ return [v[0]*s, v[1]*s, v[2]*s]; }
 function length(v){ return Math.hypot(v[0], v[1], v[2]); }

 function elementTemplate(symbol){
 const t = ELEMENTS[symbol] || ELEMENTS.X;
 return { el:symbol, color:t.color, scale:t.scale, label:t.label };
 }

 function atom(symbol, x, y, z, extra = {}){
 return Object.assign({ x, y, z }, elementTemplate(symbol), extra);
 }

 function createScene(meta){
 return Object.assign({
 id:'custom',
 title:'Cena',
 subtitle:'',
 description:'',
 cell:{a:7.1709,b:7.4209,c:8.0256,alpha:110.6,beta:115.9,gamma:100.5},
 repeat:{x:1,y:1,z:1},
 atoms:[],
 bonds:[],
 showLabels:true,
 showCell:true,
 showAxes:true
 }, meta || {});
 }

 function addAtomToScene(scene, atomObj){
 scene.atoms.push(atomObj);
 return scene.atoms.length - 1;
 }

 function addBondToScene(scene, a, b, kind='single', color='#d5deee'){
 scene.bonds.push({ a, b, kind, color });
 return scene.bonds.length - 1;
 }


 function getAtomScenePos(atomObj){
 return ((atomObj && (atomObj.manualPos || atomObj.pos)) || [atomObj?.x || 0, atomObj?.y || 0, atomObj?.z || 0]).slice();
 }

 function cross(a,b){
 return [
  a[1]*b[2] - a[2]*b[1],
  a[2]*b[0] - a[0]*b[2],
  a[0]*b[1] - a[1]*b[0]
 ];
 }

 function normalizeVec(v){
 const len = Math.hypot(v[0], v[1], v[2]) || 1;
 return [v[0]/len, v[1]/len, v[2]/len];
 }

 function scaleVec(v, s){
 return [v[0]*s, v[1]*s, v[2]*s];
 }

 function centroidOfPoints(points = []){
 if(!points.length) return [0,0,0];
 const acc = points.reduce((sum, p) => [sum[0] + p[0], sum[1] + p[1], sum[2] + p[2]], [0,0,0]);
 return [acc[0] / points.length, acc[1] / points.length, acc[2] / points.length];
 }

 function makePolyhedron(center, verts, faces, style = {}){
 return {
  center: (center || [0,0,0]).slice(),
  verts: (verts || []).map(v => v.slice()),
  faces: (faces || []).map(face => face.slice()),
  color: style.color || '#81b2d6',
  alpha: style.alpha == null ? 0.5 : style.alpha,
  centerSym: style.centerSym || 'X',
  centerLabel: style.centerLabel || style.centerSym || 'X'
 };
 }

 function uniqueNeighborIds(ids = []){
 return Array.from(new Set((ids || []).filter(v => v != null)));
 }

 function bondedNeighborIndices(scene, centerIdx, predicate = null){
 const out = [];
 (scene?.bonds || []).forEach(bd => {
  let other = null;
  if(bd.a === centerIdx) other = bd.b;
  else if(bd.b === centerIdx) other = bd.a;
  if(other == null) return;
  const atomObj = scene?.atoms?.[other];
  if(!atomObj) return;
  if(predicate && !predicate(atomObj, other)) return;
  out.push(other);
 });
 return uniqueNeighborIds(out);
 }

 const TETRAHEDRON_FACE_TEMPLATE = [[0,1,2],[0,3,1],[1,3,2],[2,3,0]];
 const OCTAHEDRON_FACE_TEMPLATE = [[0,2,4],[2,1,4],[1,3,4],[3,0,4],[2,0,5],[1,2,5],[3,1,5],[0,3,5]];
 const CUBE_FACE_TEMPLATE = [[3,2,1],[3,1,0],[5,1,0],[5,4,0],[7,3,0],[7,4,0],[6,2,1],[6,5,1],[6,3,2],[6,7,3],[6,5,4],[6,7,4]];
 const CIS_SQUARE_PRISM_FACES = [[0,1,2],[0,2,3],[4,6,5],[4,7,6],[0,4,5],[0,5,1],[1,5,6],[1,6,2],[2,6,7],[2,7,3],[3,7,4],[3,4,0]];
