 function assignOctahedralVertexMap(center, verts){
 const slots = { px:null, nx:null, py:null, ny:null, pz:null, nz:null };
 (verts || []).forEach(v => {
  const rel = sub(v, center);
  const ax = [Math.abs(rel[0]), Math.abs(rel[1]), Math.abs(rel[2])];
  let key = 'px';
  if(ax[0] >= ax[1] && ax[0] >= ax[2]) key = rel[0] >= 0 ? 'px' : 'nx';
  else if(ax[1] >= ax[0] && ax[1] >= ax[2]) key = rel[1] >= 0 ? 'py' : 'ny';
  else key = rel[2] >= 0 ? 'pz' : 'nz';
  if(!slots[key]) slots[key] = v.slice();
 });
 const ordered = [slots.px, slots.nx, slots.py, slots.ny, slots.pz, slots.nz];
 return ordered.every(Boolean) ? ordered : null;
 }

 function buildOctahedronPolyhedron(center, verts, style = {}){
 const ordered = assignOctahedralVertexMap(center, verts);
 if(!ordered) return null;
 return makePolyhedron(center, ordered, OCTAHEDRON_FACE_TEMPLATE, style);
 }

 function buildTetrahedronPolyhedron(center, verts, style = {}){
 const ordered = (verts || []).slice(0, 4).map(v => v.slice());
 if(ordered.length < 4) return null;
 return makePolyhedron(center || centroidOfPoints(ordered), ordered, TETRAHEDRON_FACE_TEMPLATE, style);
 }

 function uniquePoints(points = [], precision = 4){
  const seen = new Set();
  const out = [];
  (points || []).forEach(p => {
   const key = (p || []).map(v => Number(v).toFixed(precision)).join('|');
   if(seen.has(key)) return;
   seen.add(key);
   out.push((p || []).slice());
  });
  return out;
 }

 function nearestPeriodicFractionalPositions(scene, centerIdx, donorElement, desiredCount = 6){
  const centerAtom = scene?.atoms?.[centerIdx];
  if(!centerAtom) return [];
  const center = getAtomScenePos(centerAtom);
  const candidates = [];
  (scene?.atoms || []).forEach((atomObj, idx) => {
   if(idx === centerIdx || atomObj.el !== donorElement) return;
   const raw = sub(getAtomScenePos(atomObj), center);
   const delta = [raw[0] - Math.round(raw[0]), raw[1] - Math.round(raw[1]), raw[2] - Math.round(raw[2])];
   const d = Math.hypot(delta[0], delta[1], delta[2]);
   if(d < 1e-6) return;
   candidates.push({ d, pos:add(center, delta) });
  });
  candidates.sort((a,b) => a.d - b.d);
  const out = [];
  const seen = new Set();
  candidates.forEach(item => {
   if(out.length >= desiredCount) return;
   const key = item.pos.map(v => Number(v).toFixed(4)).join('|');
   if(seen.has(key)) return;
   seen.add(key);
   out.push(item.pos.slice());
  });
  return out;
 }

 function nearestLatticePositions(basePositions, repeatBasis, site, desiredCount = 4, imageRange = 1){
  const candidates = [];
  for(let ix = -imageRange; ix <= imageRange; ix++){
   for(let iy = -imageRange; iy <= imageRange; iy++){
    for(let iz = -imageRange; iz <= imageRange; iz++){
     const offset = matVec(repeatBasis, [ix, iy, iz]);
     (basePositions || []).forEach(basePos => {
      const pos = add(basePos, offset);
      const d = Math.hypot(pos[0] - site[0], pos[1] - site[1], pos[2] - site[2]);
      if(d < 1e-6) return;
      candidates.push({ d, pos });
     });
    }
   }
  }
  candidates.sort((a,b) => a.d - b.d);
  const out = [];
  const seen = new Set();
  candidates.forEach(item => {
   if(out.length >= desiredCount) return;
   const key = item.pos.map(v => Number(v).toFixed(4)).join('|');
   if(seen.has(key)) return;
   seen.add(key);
   out.push(item.pos.slice());
  });
  return out;
 }

 function makeAxisOctahedron(center, rx, ry, rz, style = {}){
  const verts = [
   [center[0] + rx, center[1], center[2]],
   [center[0] - rx, center[1], center[2]],
   [center[0], center[1] + ry, center[2]],
   [center[0], center[1] - ry, center[2]],
   [center[0], center[1], center[2] + rz],
   [center[0], center[1], center[2] - rz]
  ];
  return makePolyhedron(center, verts, OCTAHEDRON_FACE_TEMPLATE, style);
 }

 function buildCisplatinPolyhedra(scene){
 const polyhedra = [];
 (scene?.atoms || []).forEach((atomObj, idx) => {
  if(atomObj.el === 'Pt'){
   const donorIds = bondedNeighborIndices(scene, idx, other => other.el === 'N' || other.el === 'Cl');
   if(donorIds.length >= 4){
    const center = getAtomScenePos(atomObj);
    const donorVerts = donorIds.slice(0, 4).map(id => getAtomScenePos(scene.atoms[id]));
    let normal = [0,0,1];
    let bestCrossLen = 0;
    for(let i = 0; i < donorVerts.length; i++){
     for(let j = i + 1; j < donorVerts.length; j++){
      const cr = cross(sub(donorVerts[i], center), sub(donorVerts[j], center));
      const len = Math.hypot(cr[0], cr[1], cr[2]);
      if(len > bestCrossLen){
       bestCrossLen = len;
       normal = normalizeVec(cr);
      }
     }
    }
    const axisX = normalizeVec(sub(donorVerts[0], center));
    let axisY = cross(normal, axisX);
    const axisYLen = Math.hypot(axisY[0], axisY[1], axisY[2]);
    axisY = axisYLen > 1e-8 ? normalizeVec(axisY) : [0,1,0];
    const ordered = donorVerts.slice().sort((a, b) => {
     const va = sub(a, center), vb = sub(b, center);
     const aa = Math.atan2(dot(va, axisY), dot(va, axisX));
     const ab = Math.atan2(dot(vb, axisY), dot(vb, axisX));
     return aa - ab;
    });
    const avgDist = ordered.reduce((sum, v) => sum + Math.hypot(v[0] - center[0], v[1] - center[1], v[2] - center[2]), 0) / Math.max(1, ordered.length);
    const thickness = Math.max(0.012, avgDist * 0.07);
    const offset = scaleVec(normal, thickness);
    const top = ordered.map(v => add(v, offset));
    const bottom = ordered.map(v => sub(v, offset));
    polyhedra.push(makePolyhedron(center, top.concat(bottom), CIS_SQUARE_PRISM_FACES, {
     color:'#8d99ff',
     alpha:0.34,
     centerSym:'Pt',
     centerLabel:'Pt'
    }));
   }
  }
  if(atomObj.el === 'N'){
   const donorIds = bondedNeighborIndices(scene, idx, other => other.el === 'H' || other.el === 'Pt');
   if(donorIds.length >= 4){
    const center = getAtomScenePos(atomObj);
    const verts = donorIds.slice(0, 4).map(id => getAtomScenePos(scene.atoms[id]));
    const tetra = buildTetrahedronPolyhedron(center, verts, {
     color:'#80dcb4',
     alpha:0.28,
     centerSym:'N',
     centerLabel:'N'
    });
    if(tetra) polyhedra.push(tetra);
   }
  }
 });
 return polyhedra;
 }

 function buildPrussianPolyhedra(scene){
 const polyhedra = [];
 (scene?.atoms || []).forEach((atomObj, idx) => {
  if(atomObj.el !== 'Fe2' && atomObj.el !== 'Fe3') return;
  const donorElement = atomObj.el === 'Fe2' ? 'C' : 'N';
  const center = getAtomScenePos(atomObj);
  const verts = nearestPeriodicFractionalPositions(scene, idx, donorElement, 6);
  if(verts.length < 6) return;
  let poly = buildOctahedronPolyhedron(center, verts, {
   color: atomObj.el === 'Fe2' ? '#ff9d66' : '#71a8ff',
   alpha: 0.22,
   centerSym: atomObj.el,
   centerLabel: atomObj.label || (atomObj.el === 'Fe2' ? 'Fe²⁺' : 'Fe³⁺')
  });
  if(!poly){
   const avg = verts.reduce((sum, v) => sum + Math.hypot(v[0]-center[0], v[1]-center[1], v[2]-center[2]), 0) / Math.max(1, verts.length);
   poly = makeAxisOctahedron(center, avg * 0.92, avg * 0.92, avg * 0.92, {
    color: atomObj.el === 'Fe2' ? '#ff9d66' : '#71a8ff',
    alpha: 0.22,
    centerSym: atomObj.el,
    centerLabel: atomObj.label || (atomObj.el === 'Fe2' ? 'Fe²⁺' : 'Fe³⁺')
   });
  }
  polyhedra.push(poly);
 });
 return polyhedra;
 }

 function buildTitaniumAlphaPolyhedra(){
  const basePositions = hcpTitaniumAtoms().map(getAtomScenePos);
  const basis = titaniumAlphaRepeatBasis();
  const polyhedra = [];

  const tetraCenters = [
   [0,0,0.195],
   [0,0,-0.195],
   [0.372,0.215,0],
   [0,0.43,0],
   [-0.372,0.215,0],
   [-0.372,-0.215,0],
   [0,-0.43,0],
   [0.372,-0.215,0]
  ];
  tetraCenters.forEach(center => {
   const verts = nearestLatticePositions(basePositions, basis, center, 4, 1);
   const tetra = buildTetrahedronPolyhedron(center, verts, {
    color:'#e7bf63',
    alpha:0.22,
    centerSym:'Ti',
    centerLabel:'Ti'
   });
   if(tetra) polyhedra.push(tetra);
  });

  polyhedra.push(makeAxisOctahedron([0,0,0], 0.44, 0.38, 0.58, {
   color:'#97dcff',
   alpha:0.18,
   centerSym:'Ti',
   centerLabel:'Ti'
  }));

  return polyhedra;
 }

 function buildTitaniumBetaPolyhedra(renderScene){
  const basePositions = (renderScene?.atoms || bccTitaniumAtoms()).map(getAtomScenePos);
  const basis = titaniumBetaRepeatBasis();
  const s = 1.32;
  const h = s * 0.5;
  const q = s * 0.25;
  const polyhedra = [];

  const octCenters = [
   [ h,0,0],[-h,0,0],[0, h,0],[0,-h,0],[0,0, h],[0,0,-h]
  ];
  octCenters.forEach(center => {
   polyhedra.push(makeAxisOctahedron(center, s * 0.14, s * 0.24, s * 0.24, {
    color:'#8cd7ff',
    alpha:0.18,
    centerSym:'Ti',
    centerLabel:'Ti'
   }));
  });

  const tetraCenters = [
   [0, q, h],[0,-q, h],[0, q,-h],[0,-q,-h],
   [ q, h,0],[-q, h,0],[ q,-h,0],[-q,-h,0],
   [ h,0, q],[ h,0,-q],[-h,0, q],[-h,0,-q]
  ];
  tetraCenters.forEach(center => {
   const verts = nearestLatticePositions(basePositions, basis, center, 4, 1);
   const tetra = buildTetrahedronPolyhedron(center, verts, {
    color:'#f0c15a',
    alpha:0.22,
    centerSym:'Ti',
    centerLabel:'Ti'
   });
   if(tetra) polyhedra.push(tetra);
  });

  return polyhedra;
 }

