 function interpolatePolyhedraLists(listA = [], listB = [], t = 0){
 const count = Math.max(listA.length, listB.length);
 const out = [];
 for(let i = 0; i < count; i++){
  const polyA = listA[i] || listA[listA.length - 1] || listB[i] || listB[listB.length - 1];
  const polyB = listB[i] || listB[listB.length - 1] || listA[i] || listA[listA.length - 1];
  if(!polyA || !polyB) continue;
  const vertsCount = Math.max((polyA.verts || []).length, (polyB.verts || []).length);
  const verts = [];
  for(let vi = 0; vi < vertsCount; vi++){
   const va = (polyA.verts && (polyA.verts[vi] || polyA.verts[polyA.verts.length - 1])) || [0,0,0];
   const vb = (polyB.verts && (polyB.verts[vi] || polyB.verts[polyB.verts.length - 1])) || [0,0,0];
   verts.push([mix(va[0], vb[0], t), mix(va[1], vb[1], t), mix(va[2], vb[2], t)]);
  }
  const cA = polyA.center || centroidOfPoints(polyA.verts || []);
  const cB = polyB.center || centroidOfPoints(polyB.verts || []);
  out.push({
   center:[mix(cA[0], cB[0], t), mix(cA[1], cB[1], t), mix(cA[2], cB[2], t)],
   verts,
   faces: clone((polyA.faces && polyA.faces.length) ? polyA.faces : (polyB.faces || [])),
   color: t < 0.5 ? (polyA.color || '#81b2d6') : (polyB.color || polyA.color || '#81b2d6'),
   alpha: mix(polyA.alpha == null ? 0.5 : polyA.alpha, polyB.alpha == null ? 0.5 : polyB.alpha, t),
   centerSym: t < 0.5 ? (polyA.centerSym || 'X') : (polyB.centerSym || polyA.centerSym || 'X'),
   centerLabel: t < 0.5 ? (polyA.centerLabel || polyA.centerSym || 'X') : (polyB.centerLabel || polyB.centerLabel || polyA.centerLabel || polyA.centerSym || 'X')
  });
 }
 return out;
 }

 function addCisplatinMolecule(scene, center, rotDeg, tiltDeg){
 const pt = [0, 0, 0];
 const n1 = [0, 0.170, 0.010];
 const n2 = [0, -0.170, -0.010];
 const cl1 = [ 0.230, 0, 0.014];
 const cl2 = [-0.230, 0, -0.014];

 const hN1a = [ 0.090, 0.250, 0.078];
 const hN1b = [-0.090, 0.250, 0.078];
 const hN1c = [ 0.000, 0.238, -0.095];

 const hN2a = [ 0.090, -0.250, -0.078];
 const hN2b = [-0.090, -0.250, -0.078];
 const hN2c = [ 0.000, -0.238, 0.095];

 const localPoints = { pt, n1, n2, cl1, cl2, hN1a, hN1b, hN1c, hN2a, hN2b, hN2c };
 const points = {};
 Object.entries(localPoints).forEach(([key, p]) => {
 let v = rotZ(p, deg(rotDeg));
 v = rotX(v, deg(tiltDeg));
 points[key] = [center[0] + v[0], center[1] + v[1], center[2] + v[2]];
 });

 const ids = {
 pt: addAtomToScene(scene, atom('Pt', points.pt[0], points.pt[1], points.pt[2])),
 n1: addAtomToScene(scene, atom('N', points.n1[0], points.n1[1], points.n1[2])),
 n2: addAtomToScene(scene, atom('N', points.n2[0], points.n2[1], points.n2[2])),
 cl1: addAtomToScene(scene, atom('Cl', points.cl1[0], points.cl1[1], points.cl1[2])),
 cl2: addAtomToScene(scene, atom('Cl', points.cl2[0], points.cl2[1], points.cl2[2])),
 h1a: addAtomToScene(scene, atom('H', points.hN1a[0], points.hN1a[1], points.hN1a[2])),
 h1b: addAtomToScene(scene, atom('H', points.hN1b[0], points.hN1b[1], points.hN1b[2])),
 h1c: addAtomToScene(scene, atom('H', points.hN1c[0], points.hN1c[1], points.hN1c[2])),
 h2a: addAtomToScene(scene, atom('H', points.hN2a[0], points.hN2a[1], points.hN2a[2])),
 h2b: addAtomToScene(scene, atom('H', points.hN2b[0], points.hN2b[1], points.hN2b[2])),
 h2c: addAtomToScene(scene, atom('H', points.hN2c[0], points.hN2c[1], points.hN2c[2]))
 };

 addBondToScene(scene, ids.pt, ids.n1, 'single', '#ffffff');
 addBondToScene(scene, ids.pt, ids.n2, 'single', '#ffffff');
 addBondToScene(scene, ids.pt, ids.cl1, 'single', '#ffffff');
 addBondToScene(scene, ids.pt, ids.cl2, 'single', '#ffffff');

 addBondToScene(scene, ids.n1, ids.h1a, 'single', '#ffffff');
 addBondToScene(scene, ids.n1, ids.h1b, 'single', '#ffffff');
 addBondToScene(scene, ids.n1, ids.h1c, 'single', '#ffffff');
 addBondToScene(scene, ids.n2, ids.h2a, 'single', '#ffffff');
 addBondToScene(scene, ids.n2, ids.h2b, 'single', '#ffffff');
 addBondToScene(scene, ids.n2, ids.h2c, 'single', '#ffffff');

 return ids;
 }

