 function fitAtomsIntoCell(scene, pad=0.06, atomIds=null){
 const ids = atomIds && atomIds.length ? atomIds : scene.atoms.map((_, i) => i);
 if(!ids.length) return scene;

 const mins = [ Infinity, Infinity, Infinity];
 const maxs = [-Infinity, -Infinity, -Infinity];

 ids.forEach(id => {
 const a = scene.atoms[id];
 mins[0] = Math.min(mins[0], a.x); maxs[0] = Math.max(maxs[0], a.x);
 mins[1] = Math.min(mins[1], a.y); maxs[1] = Math.max(maxs[1], a.y);
 mins[2] = Math.min(mins[2], a.z); maxs[2] = Math.max(maxs[2], a.z);
 });

 const spans = [
 Math.max(1e-9, maxs[0] - mins[0]),
 Math.max(1e-9, maxs[1] - mins[1]),
 Math.max(1e-9, maxs[2] - mins[2])
 ];
 const maxSpan = Math.max(spans[0], spans[1], spans[2], 1e-9);
 const inner = Math.max(0.02, 1 - pad * 2);
 const scale = inner / maxSpan;
 const center = [
 (mins[0] + maxs[0]) * 0.5,
 (mins[1] + maxs[1]) * 0.5,
 (mins[2] + maxs[2]) * 0.5
 ];

 ids.forEach(id => {
 const a = scene.atoms[id];
 a.x = 0.5 + (a.x - center[0]) * scale;
 a.y = 0.5 + (a.y - center[1]) * scale;
 a.z = 0.5 + (a.z - center[2]) * scale;
 });

 return scene;
 }

