 function addSharedSceneAtom(scene, cache, symbol, pos, extra = {}){
 const key = `${symbol}:${pos.map(v => Number(v).toFixed(3)).join('|')}`;
 if(cache.has(key)) return cache.get(key);
 const idx = addAtomToScene(scene, atom(symbol, pos[0], pos[1], pos[2], extra));
 cache.set(key, idx);
 return idx;
 }

 function buildFrameworkScene(opts){
 const scene = createScene({
 id:opts.id,
 title:opts.title,
 subtitle:opts.subtitle,
 description:opts.description,
 cell:opts.cell,
 repeat:{x:1,y:1,z:1},
 showLabels:false,
 showCell:true
 });

 const cache = new Map();
 const labelFor = symbol => (ELEMENTS[symbol] && ELEMENTS[symbol].label) ? ELEMENTS[symbol].label.replace('⁺','') : symbol;

 (opts.centers || []).forEach(center => {
 const cIdx = addSharedSceneAtom(scene, cache, center.symbol, center.pos, { label:labelFor(center.symbol) });
 (center.neighbors || []).forEach(pos => {
 const oIdx = addSharedSceneAtom(scene, cache, 'O', pos, { label:'O' });
 addBondToScene(scene, cIdx, oIdx, 'single', '#ffffff');
 });
 });

 (opts.linkBonds || []).forEach(link => {
 const a = addSharedSceneAtom(scene, cache, link[0].symbol || 'O', link[0].pos || link[0], { label:labelFor(link[0].symbol || 'O') });
 const b = addSharedSceneAtom(scene, cache, link[1].symbol || 'O', link[1].pos || link[1], { label:labelFor(link[1].symbol || 'O') });
 addBondToScene(scene, a, b, 'single', '#ffffff');
 });

 (opts.extraAtoms || []).forEach(extra => {
 addSharedSceneAtom(scene, cache, extra.symbol, extra.pos, { label:labelFor(extra.symbol) });
 });

 (opts.hydrogens || []).forEach(pair => {
 const oIdx = addSharedSceneAtom(scene, cache, 'O', pair.o, { label:'O' });
 const hIdx = addSharedSceneAtom(scene, cache, 'H', pair.h, { label:'H' });
 addBondToScene(scene, oIdx, hIdx, 'single', '#ffffff');
 });

 if(opts.view) scene.view = clone(opts.view);
 return scene;
 }

