function buildExtractedPolymorph(key, meta){
 const data = AL2SIO5_POLYMORPHS[key];
 const scene = createScene({
 id:key,
 title:meta.title,
 subtitle:meta.subtitle,
 description:meta.description,
 cell:clone(data.cell),
 repeat:{x:1,y:1,z:1},
 showLabels:false,
 showCell:true
 });
 scene.atoms = data.atoms.map(a => atom(a.sym, 0, 0, 0, {
 manualPos:a.pos.slice(),
 label:a.label,
 legendName:a.label,
 color:a.color,
 scale:a.scale
 }));
 scene.bonds = data.bonds.map(([a,b]) => ({ a, b, kind:'single', color:'#ffffff' }));
 let min=[ Infinity, Infinity, Infinity];
 data.cellEdges.forEach(edge => {
 const pa = (edge.a || edge[0]).slice();
 const pb = (edge.b || edge[1]).slice();
 min[0] = Math.min(min[0], pa[0], pb[0]);
 min[1] = Math.min(min[1], pa[1], pb[1]);
 min[2] = Math.min(min[2], pa[2], pb[2]);
 });
 scene.baseCell = clone(data.cell);
 scene.baseManualAtoms = scene.atoms.map(at => Object.assign({}, at, { manualPos:(at.manualPos || [at.x || 0, at.y || 0, at.z || 0]).slice() }));
 scene.basePolyhedra = clone(POLYHEDRA_BY_SCENE[key] || []);
 scene.baseManualOrigin = min.slice();
 scene.baseManualBasis = cellMatrix(data.cell.a, data.cell.b, data.cell.c, data.cell.alpha, data.cell.beta, data.cell.gamma);
 scene.baseCellEdges = data.cellEdges.map(edge => ({ a:(edge.a || edge[0]).slice(), b:(edge.b || edge[1]).slice() }));
 scene.customWorldBuilder = (renderScene) => buildResponsiveManualWorld(renderScene);
 scene.view = clone(meta.view || { yaw:-0.84, pitch:0.24, zoom:1.15 });
 return scene;
}

