function worldBounds(world){
 let min=[ Infinity, Infinity, Infinity];
 let max=[-Infinity,-Infinity,-Infinity];
 const push = p => {
  min[0] = Math.min(min[0], p[0]); min[1] = Math.min(min[1], p[1]); min[2] = Math.min(min[2], p[2]);
  max[0] = Math.max(max[0], p[0]); max[1] = Math.max(max[1], p[1]); max[2] = Math.max(max[2], p[2]);
 };
 (world.atoms || []).forEach(at => push(at.pos));
 (world.cellEdges || []).forEach(edge => { push(edge.a); push(edge.b); });
 (world.polyhedra || []).forEach(poly => (poly.verts || []).forEach(push));
 if(!isFinite(min[0])) return { min:[-0.5,-0.5,-0.5], max:[0.5,0.5,0.5], center:[0,0,0], size:[1,1,1] };
 return {
  min,
  max,
  center:[(min[0]+max[0])/2, (min[1]+max[1])/2, (min[2]+max[2])/2],
  size:[max[0]-min[0], max[1]-min[1], max[2]-min[2]]
 };
}

function layoutWorldsHorizontally(worlds, gapFactor = 0.38){
 const bounds = worlds.map(worldBounds);
 const widths = bounds.map(b => Math.max(0.8, b.size[0]));
 const maxW = Math.max(...widths, 1);
 const gap = maxW * gapFactor;
 let cursor = -(widths.reduce((acc, w) => acc + w, 0) + gap * Math.max(0, widths.length - 1)) / 2;
 return worlds.map((world, idx) => {
  const b = bounds[idx];
  const centerX = cursor + widths[idx] / 2;
  cursor += widths[idx] + gap;
  return [centerX - b.center[0], -b.center[1], -b.center[2]];
 });
}

function mergeWorldsWithOffsets(worlds, offsets){
 const entries = [];
 const bonds = [];
 const cellEdges = [];
 const polyhedra = [];
 worlds.forEach((world, idx) => {
  const offset = (offsets[idx] || [0,0,0]).slice();
  (world.atoms || []).forEach(at => {
   const nextAtom = Object.assign({}, at.atom || {}, { manualPos:add(at.pos, offset) });
   entries.push(nextAtom);
  });
  (world.bonds || []).forEach(bd => {
   bonds.push({ a:add(bd.a, offset), b:add(bd.b, offset), kind:bd.kind || 'single', color:bd.color || '#ffffff' });
  });
  (world.cellEdges || []).forEach(edge => {
   cellEdges.push({ a:add(edge.a, offset), b:add(edge.b, offset) });
  });
  (world.polyhedra || []).forEach(poly => {
   polyhedra.push({
    center: add(poly.center || [0,0,0], offset),
    verts: (poly.verts || []).map(v => add(v, offset)),
    faces: (poly.faces || []).map(face => face.slice()),
    color: poly.color || '#81b2d6',
    alpha: poly.alpha == null ? 0.5 : poly.alpha,
    centerSym: poly.centerSym || 'X',
    centerLabel: poly.centerLabel || poly.centerSym || 'X'
   });
  });
 });
 return buildManualWorld(entries, cellEdges, bonds, { polyhedra });
}

function makeComparisonScene(meta, sceneFactoryList, gapFactor = 0.38){
 const previewChildScenes = sceneFactoryList.map(factory => factory());
 const previewChildWorlds = previewChildScenes.map(child => buildWorld(child));
 const previewOffsets = layoutWorldsHorizontally(previewChildWorlds, gapFactor);
 const previewWorld = mergeWorldsWithOffsets(previewChildWorlds, previewOffsets);
 const scene = createScene({
  id:meta.id,
  title:meta.title,
  subtitle:meta.subtitle,
  description:meta.description,
  cell:{a:1,b:1,c:1,alpha:90,beta:90,gamma:90},
  repeat:{x:1,y:1,z:1},
  showLabels:false,
  showCell:true
 });
 scene.atoms = previewWorld.atoms.map(entry => Object.assign({}, entry.atom || {}, { manualPos:entry.pos.slice() }));
 scene.bonds = previewWorld.bonds.map(bd => ({ a:bd.a.slice(), b:bd.b.slice(), kind:bd.kind || 'single', color:bd.color || '#ffffff' }));
 scene.customWorldBuilder = (renderScene) => {
  const childScenes = sceneFactoryList.map(factory => factory());
  childScenes.forEach(child => {
   child.repeat = clone(renderScene.repeat || {x:1,y:1,z:1});
   child.showCell = renderScene.showCell;
  });
  const childWorlds = childScenes.map(child => buildWorld(child));
  const offsets = layoutWorldsHorizontally(childWorlds, gapFactor);
  return mergeWorldsWithOffsets(childWorlds, offsets);
 };
 scene.view = clone(meta.view || { yaw:-0.76, pitch:0.22, zoom:0.82 });
 return scene;
}

