function buildSceneFromExtractedData(key, meta){
 const data = GLB_EXTRACTED_STRUCTURES[key];
 const scene = createScene({
  id: meta.id || key,
  title: meta.title,
  subtitle: meta.subtitle,
  description: meta.description,
  cell: clone(data.cell),
  repeat: {x:1,y:1,z:1},
  showLabels: false,
  showCell: true
 });
 scene.atoms = data.atoms.map(a => atom(a.sym, 0, 0, 0, {
  manualPos: a.pos.slice(),
  label: a.label,
  legendName: a.label,
  color: a.color,
  scale: a.scale
 }));
 scene.bonds = data.bonds.map(([a,b]) => ({ a, b, kind:'single', color:'#ffffff' }));
 scene.baseCell = clone(data.cell);
 scene.baseManualAtoms = scene.atoms.map(at => Object.assign({}, at, { manualPos:(at.manualPos || [at.x || 0, at.y || 0, at.z || 0]).slice() }));
 scene.basePolyhedra = clone(POLYHEDRA_BY_SCENE[key] || []);
 scene.baseManualOrigin = data.origin.slice();
 scene.baseManualBasis = clone(data.basis);
 scene.baseCellEdges = data.cellEdges.map(edge => ({ a:(edge.a || edge[0]).slice(), b:(edge.b || edge[1]).slice() }));
 scene.customWorldBuilder = renderScene => buildResponsiveManualWorld(renderScene);
 scene.view = clone(meta.view || { yaw:-0.82, pitch:0.24, zoom:1.0 });
 if(meta.uiDefaults) scene.uiDefaults = clone(meta.uiDefaults);
 return scene;
}

