function defaultScene(){
 return PRESETS.quartz();
}

 function loadStoredScene(){
 try{
 const raw = localStorage.getItem(STORAGE_KEY);
 if(!raw) return defaultScene();
 const parsed = JSON.parse(raw);
 if(!parsed || !parsed.atoms || !parsed.bonds || !parsed.cell) return defaultScene();
 if(parsed.id && PRESETS[parsed.id]) return PRESETS[parsed.id]();
 return parsed;
 } catch(err){
 return defaultScene();
 }
 }

 let scene = loadStoredScene();
 let sceneBaseId = scene.id || 'quartz';

